  ('optometrist-moex-01133', 'optometrist', 'optometrist-moex-110-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '進行視網膜檢影鏡檢查時，若在患者之眼底反光中觀察到剪刀式反光（scissors’sreflex）可能是由於光學像 差，如：彗星像差所引起的。則下列那一類型患者眼前進行視網膜檢影鏡檢查時，較不會觀察到剪刀式反 光？', '["圓錐角膜（keratoconus）", "角膜結痂（cornealscarring）", "縮瞳（miosis）", "高度近視（highmyopia）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "f7e14c4682c6", "answer_pdf_sha1": "4e066a5b533e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
